-- Case 06: multilingual text, quoted identifiers, Unicode normalization traps,
-- right-to-left strings, emoji, combining marks, and embedded JSON.
Create Or Replace TEMPORARY Table CORE."多言語_顧客ラベル" ("顧客ID" VARCHAR Not Null, "表示名" VARCHAR, "日本語" VARCHAR, "한국어" VARCHAR, "简体中文" VARCHAR, "العربية" VARCHAR, "עברית" VARCHAR, "हिन्दी" VARCHAR, "ภาษาไทย" VARCHAR, "emoji_😀" VARCHAR, "metadata_メタデータ" variant, created_at TIMESTAMP_TZ Default CURRENT_TIMESTAMP());
Insert Into CORE."多言語_顧客ラベル" ("顧客ID", "表示名", "日本語", "한국어", "简体中文", "العربية", "עברית", "हिन्दी", "ภาษาไทย", "emoji_😀", "metadata_メタデータ") Select column1, column2, column3, column4, column5, column6, column7, column8, column9, column10, PARSE_JSON(column11) from values ('C-JP-001', '杉野尾 広貴', '東京都で「雪」と桜を見る。', '서울에서 데이터 파이프라인을 운영합니다.', '你好，世界；数据工程。', 'مرحبًا بالعالم — هندسة البيانات', 'שלום עולם — הנדסת נתונים', 'नमस्ते दुनिया — डेटा इंजीनियरिंग', 'สวัสดีชาวโลก — วิศวกรรมข้อมูล', '👩🏽‍💻🚀📦✅', '{"locale":"ja-JP","tags":["雪","데이터","بيانات"],"nested":{"fullwidth":"ＡＢＣ１２３","nfd":"Café"}}'), ('C-EU-002', 'Élodie d''Arcy', 'L''été, le café et la crème brûlée.', '따옴표 '' 및 세미콜론 ; 테스트', '引号“测试”、分号；以及换行', 'اختبار علامات الاقتباس '' والفاصلة المنقوطة ؛', 'בדיקת ציטוטים '' ונקודה-פסיק ;', 'उद्धरण '' और अर्धविराम ; परीक्षण', 'ทดสอบอัญประกาศ '' และอัฒภาค ;', '🏳️‍🌈👨‍👩‍👧‍👦🧪', '{"locale":"fr-FR","currency":"EUR","rtl":false,"text":"line1\\nline2\\tend"}');
Select "顧客ID" as customer_id, "表示名" As display_name, LENGTH("表示名") As character_count, OCTET_LENGTH("表示名") As utf8_byte_count, REGEXP_REPLACE("表示名", '[[:space:]]+', ' ') as collapsed_spaces, "metadata_メタデータ":nested.fullwidth::STRING As fullwidth_text, "metadata_メタデータ":nested.nfd::STRING as potentially_decomposed_text, ARRAY_SIZE("metadata_メタデータ":tags) As tag_count, OBJECT_KEYS("metadata_メタデータ") as metadata_keys, Case When "العربية" Is Not Null Then 'rtl-and-ltr-mixed' When "עברית" Is Not Null Then 'hebrew-present' else 'other' end as direction_test, CONCAT_WS(' | ', NULLIF("日本語", ''), NULLIF("한국어", ''), NULLIF("简体中文", ''), NULLIF("العربية", ''), NULLIF("עברית", '')) As multilingual_summary From CORE."多言語_顧客ラベル" Where "日本語" Collate 'en-ci' Ilike '%データ%' Or "한국어" Ilike '%데이터%' Or "العربية" Ilike '%بيانات%' order by "表示名" collate 'en-ci';
Select label."顧客ID", tag.index As tag_index, tag.value::STRING As tag_value, TYPEOF(tag.value) As tag_type From CORE."多言語_顧客ラベル" As label, lateral FLATTEN(INPUT => label."metadata_メタデータ":tags, Outer => true) As tag Order By label."顧客ID", tag.index;
